1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
4	const BLOCK_OF_THREE_DISCOUNT = 15;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string; cursed?: boolean };
16	type QuoteStep = { op: "quote"; items: Array<Item> };
17	type Scenario = {
18	  customer: { yearsWithMHPCO: number };
19	  steps: Array<QuoteStep>;
20	};
21	
22	const roundUpInMHPCOFavor = (amount: number): number =>
23	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
24	
25	const CURSE_SURCHARGE = 0.5;
26	
27	const itemSurcharges = (item: Item): number => {
28	  const base = BASE_PREMIUM[item.type];
29	  return item.cursed ? base * CURSE_SURCHARGE : 0;
30	};
31	
32	const sumOfBasePrices = (items: Array<Item>): number =>
33	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
34	
35	const sumOfItemSurcharges = (items: Array<Item>): number =>
36	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
37	
38	const COMPONENT_TYPES = ["rune", "moonstone"];
39	const BLOCK_SIZE = 3;
40	
41	const countOfType = (items: Array<Item>, type: string): number =>
42	  items.filter((item) => item.type === type).length;
43	
44	const formsABlock = (items: Array<Item>, type: string): boolean =>
45	  countOfType(items, type) === BLOCK_SIZE;
46	
47	const blockDiscountFor = (items: Array<Item>): number =>
48	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
49	  BLOCK_OF_THREE_DISCOUNT;
50	
51	const basePremiumFor = (items: Array<Item>): number =>
52	  sumOfBasePrices(items) - blockDiscountFor(items);
53	
54	const withFirstInsuranceSurcharge = (amount: number): number =>
55	  amount * (1 + FIRST_INSURANCE_SURCHARGE);
56	
57	const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;
58	
59	const quoteStep = (step: QuoteStep): { premium: number } => {
60	  const basePremium = basePremiumFor(step.items);
61	  const itemSurchargeTotal = sumOfItemSurcharges(step.items);
62	  const premiumBeforeRounding = withProcessingFee(
63	    withFirstInsuranceSurcharge(basePremium) + itemSurchargeTotal,
64	  );
65	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
66	};
67	
68	export const processScenario = (scenario: unknown): unknown => {
69	  const { steps } = scenario as Scenario;
70	  return { results: steps.map(quoteStep) };
71	};
